headStyles:
body { background: var(--dark-bg); }

/* ============================================================
   BOARD HERO — "10 Fierce Ohioans"
   ============================================================ */
.board-hero {
  position: relative;
  padding: calc(var(--nav-height) + 72px) 24px 72px;
  overflow: hidden;
  text-align: center;
}
.board-hero::before {
  content: '';
  position: absolute;
  inset: 0;
  background:
    radial-gradient(ellipse at 20% 10%, rgba(115, 215, 238, 0.12), transparent 45%),
    radial-gradient(ellipse at 85% 15%, rgba(117, 7, 135, 0.15), transparent 50%),
    radial-gradient(ellipse at 50% 100%, rgba(0, 77, 255, 0.12), transparent 55%);
  z-index: 0;
}
.board-hero-inner {
  position: relative;
  z-index: 1;
  max-width: 980px;
  margin: 0 auto;
}
.board-hero .eyebrow {
  font-family: 'Montserrat', sans-serif;
  font-size: 12px;
  font-weight: 700;
  letter-spacing: 3.5px;
  text-transform: uppercase;
  color: var(--text-accent);
  margin-bottom: 20px;
  display: inline-block;
  padding: 8px 16px;
  border: 1px solid rgba(115, 215, 238, 0.3);
  border-radius: 999px;
  background: rgba(115, 215, 238, 0.06);
}

/* The giant "10" number */
.hero-10 {
  font-family: 'Montserrat', sans-serif;
  font-weight: 900;
  font-size: clamp(120px, 24vw, 280px);
  line-height: 0.85;
  letter-spacing: -0.04em;
  background: var(--pride-gradient);
  background-size: 200% 200%;
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  margin: 0 auto 8px;
  animation: gradientShift 8s ease infinite;
  text-shadow: 0 0 80px rgba(115, 215, 238, 0.15);
}
@keyframes gradientShift {
  0%, 100% { background-position: 0% 50%; }
  50% { background-position: 100% 50%; }
}

/* "FIERCE" rotator */
.hero-fierce-line {
  font-family: 'Montserrat', sans-serif;
  font-weight: 800;
  font-size: clamp(28px, 5vw, 56px);
  color: var(--text-white);
  line-height: 1.1;
  letter-spacing: -0.01em;
  margin-bottom: 14px;
}
.hero-fierce-word {
  display: inline-block;
  position: relative;
  padding: 0 6px;
  background: var(--pride-gradient);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  font-style: italic;
}
.hero-fierce-word::after {
  content: '';
  position: absolute;
  left: 0;
  right: 0;
  bottom: 6%;
  height: 3px;
  background: var(--pride-gradient);
  opacity: 0.55;
  border-radius: 2px;
  transform-origin: left;
  animation: slashIn 1s ease 0.5s both;
}
@keyframes slashIn {
  from { transform: scaleX(0); }
  to { transform: scaleX(1); }
}

.hero-sub {
  font-family: 'Roboto Slab', serif;
  font-size: clamp(15px, 1.8vw, 18px);
  color: var(--text-light);
  line-height: 1.6;
  max-width: 640px;
  margin: 0 auto 32px;
}

/* Marquee name strip */
.name-strip {
  position: relative;
  overflow: hidden;
  padding: 18px 0;
  border-top: 1px solid var(--border-light);
  border-bottom: 1px solid var(--border-light);
  background: rgba(0, 0, 0, 0.12);
  mask-image: linear-gradient(to right, transparent, black 8%, black 92%, transparent);
  -webkit-mask-image: linear-gradient(to right, transparent, black 8%, black 92%, transparent);
}
.name-strip-track {
  /* `flex` + `width: max-content` is the canonical marquee pattern.
     `inline-flex` was inconsistent across browsers and could collapse
     to the parent's content width, killing the scroll. */
  display: flex;
  width: max-content;
  white-space: nowrap;
  animation: marquee 45s linear infinite;
}
@keyframes marquee {
  from { transform: translateX(0); }
  to { transform: translateX(-50%); }
}
.name-strip-item {
  font-family: 'Montserrat', sans-serif;
  font-size: 14px;
  font-weight: 700;
  letter-spacing: 2px;
  text-transform: uppercase;
  color: rgba(255, 255, 255, 0.7);
  /* Per-item right padding instead of `gap` on the track. This keeps
     both halves of the doubled track identical, so translateX(-50%)
     lines up exactly and the loop is seamless. */
  padding-right: 48px;
  flex-shrink: 0;
}
.name-strip-dot {
  color: var(--text-accent);
  font-weight: 900;
}
@media (prefers-reduced-motion: reduce) {
  .name-strip-track { animation-duration: 120s; }
  .hero-10 { animation: none; }
  .hero-fierce-word::after { animation: none; transform: scaleX(1); }
}

/* Board stats */
.board-stats {
  display: flex;
  gap: 48px;
  justify-content: center;
  padding: 56px 0 24px;
  flex-wrap: wrap;
}
.board-stat { text-align: center; }
.board-stat-num {
  font-family: 'Montserrat', sans-serif;
  font-size: 40px;
  font-weight: 800;
  background: var(--pride-gradient);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  line-height: 1;
  margin-bottom: 8px;
}
.board-stat-label {
  font-family: 'Montserrat', sans-serif;
  font-size: 11px;
  font-weight: 600;
  letter-spacing: 1.8px;
  text-transform: uppercase;
  color: var(--text-muted);
}

/* ============================================================
   BOARD GRID
   ============================================================ */
.board-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(280px, 1fr));
  gap: 28px;
  /* Default grid align-items is `stretch`, so if one card's bio
     expands the rest of that row stretches to match. `start` lets
     each card size to its own content and keeps the collapsed cards
     from growing with their neighbor. */
  align-items: start;
}
.board-card {
  background: var(--bg-white);
  border: 1px solid var(--border-light);
  border-radius: 14px;
  overflow: hidden;
  transition: transform 0.35s cubic-bezier(0.25, 0.46, 0.45, 0.94), box-shadow 0.35s ease, border-color 0.35s ease;
  position: relative;
  display: flex;
  flex-direction: column;
}
.board-card::after {
  content: '';
  position: absolute;
  bottom: 0; left: 0; right: 0;
  height: 3px;
  background: var(--pride-gradient);
  transform: scaleX(0);
  transform-origin: center;
  transition: transform 0.4s ease;
}
.board-card:hover::after,
.board-card.is-open::after { transform: scaleX(1); }
.board-card:hover {
  transform: translateY(-5px);
  box-shadow: 0 16px 48px rgba(0, 0, 0, 0.25);
  border-color: rgba(115, 215, 238, 0.25);
}

/* Avatar */
.board-card-avatar {
  width: 100%;
  aspect-ratio: 1;
  background: var(--dark-bg-light);
  position: relative;
  overflow: hidden;
}
.board-card-avatar img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  object-position: center top;
  display: block;
  transition: transform 0.5s ease;
}
.board-card-avatar img[src*="zach-joseph"] {
  object-position: center 22%;
}
.board-card:hover .board-card-avatar img {
  transform: scale(1.04);
}
.avatar-gradient {
  position: absolute;
  inset: 0;
  background: linear-gradient(to bottom, transparent 55%, rgba(15, 34, 51, 0.85) 100%);
  pointer-events: none;
}
.board-card-chip {
  position: absolute;
  top: 14px;
  left: 14px;
  font-family: 'Montserrat', sans-serif;
  font-size: 10px;
  font-weight: 700;
  letter-spacing: 1.5px;
  text-transform: uppercase;
  padding: 6px 12px;
  border-radius: 999px;
  background: rgba(15, 34, 51, 0.72);
  backdrop-filter: blur(8px);
  -webkit-backdrop-filter: blur(8px);
  border: 1px solid rgba(255, 255, 255, 0.15);
  color: #ffffff;
}
.board-card-chip.is-director { color: var(--color-light-blue); border-color: rgba(115, 215, 238, 0.4); }
.board-card-chip.is-treasurer { color: var(--color-yellow); border-color: rgba(255, 237, 0, 0.4); }
.board-card-chip.is-secretary { color: #ffafc8; border-color: rgba(255, 175, 200, 0.4); }
.board-card-chip.is-comms { color: #c084fc; border-color: rgba(192, 132, 252, 0.4); }

.board-card-info {
  padding: 22px 22px 6px;
}
.board-card-name {
  font-family: 'Montserrat', sans-serif;
  font-size: 18px;
  font-weight: 700;
  color: var(--text-white);
  margin-bottom: 4px;
  line-height: 1.25;
}
.board-card-role {
  font-family: 'Montserrat', sans-serif;
  font-size: 12px;
  font-weight: 600;
  letter-spacing: 1.4px;
  text-transform: uppercase;
  color: var(--text-muted);
  margin-bottom: 14px;
}

/* Bio area.
   Collapsed state is animated via max-height + opacity + vertical
   padding rather than `display: none`, so opening and closing the
   panel smoothly expands the card instead of snapping to its final
   height. The `align-items: start` on .board-grid keeps the rest of
   the row from reacting to the change in this card's height. */
.board-card-bio {
  padding: 0 22px;
  color: var(--text-secondary);
  font-size: 14.5px;
  line-height: 1.7;
  max-height: 0;
  opacity: 0;
  overflow: hidden;
  transition: max-height 0.4s cubic-bezier(0.25, 0.46, 0.45, 0.94),
              opacity 0.3s ease,
              padding 0.3s ease;
}
.board-card-bio p + p { margin-top: 0.8rem; }
.board-card.is-open .board-card-bio {
  /* 1600px is comfortably larger than the longest seeded bio and
     avoids the layout-thrash that comes with `max-height: auto`. */
  max-height: 1600px;
  opacity: 1;
  padding-top: 0;
  padding-bottom: 22px;
}

.board-card-toggle {
  margin: 0 22px 20px;
  align-self: flex-start;
  background: none;
  border: 1px solid rgba(115, 215, 238, 0.35);
  color: var(--color-light-blue);
  font-family: 'Montserrat', sans-serif;
  font-size: 12px;
  font-weight: 700;
  letter-spacing: 1.2px;
  text-transform: uppercase;
  padding: 9px 16px;
  border-radius: 999px;
  cursor: pointer;
  transition: all 0.25s ease;
  display: inline-flex;
  align-items: center;
  gap: 8px;
}
.board-card-toggle:hover {
  background: rgba(115, 215, 238, 0.12);
  border-color: var(--color-light-blue);
  color: var(--color-white);
}
.board-card-toggle svg {
  transition: transform 0.3s ease;
}
.board-card.is-open .board-card-toggle svg {
  transform: rotate(180deg);
}

/* Join CTA */
.join-cta {
  background: var(--bg-white);
  border: 1px solid var(--border-light);
  border-radius: 14px;
  padding: 48px;
  text-align: center;
  margin-top: 72px;
  position: relative;
  overflow: hidden;
}
.join-cta::before {
  content: '';
  position: absolute;
  top: 0; left: 0; right: 0;
  height: 4px;
  background: var(--pride-gradient);
}
.join-cta h2 { font-size: 26px; margin-bottom: 12px; }
.join-cta p {
  font-size: 16px;
  color: var(--text-secondary);
  max-width: 520px;
  margin: 0 auto 28px;
  line-height: 1.65;
}

@media (max-width: 768px) {
  .board-hero { padding-top: calc(var(--nav-height) + 40px); padding-bottom: 48px; }
  .board-grid { grid-template-columns: repeat(auto-fill, minmax(240px, 1fr)); gap: 20px; }
  .board-stats { gap: 28px; padding-top: 40px; }
  .board-stat-num { font-size: 30px; }
  .join-cta { padding: 32px 24px; margin-top: 48px; }
  .hero-fierce-line { font-size: clamp(22px, 6vw, 34px); }
}
